import java.io.*;class Main{static long count(long n,long p){long steps=0,first=p,next=p+1;while(first<=n){steps+=Math.min(n+1,next)-first;first*=10;next*=10;}return steps;}static long kth(long n,long k){long cur=1;k--;while(k>0){long steps=count(n,cur);if(steps<=k){cur++;k-=steps;}else{cur*=10;k--;}}return cur;}public static void main(String[]args)throws Exception{String text=new String(System.in.readAllBytes()).trim();if(text.isEmpty())return;String[]d=text.split("\\s+");int idx=0,t=Integer.parseInt(d[idx++]);StringBuilder out=new StringBuilder();for(int tc=0;tc<t;tc++){long n=Long.parseLong(d[idx++]),k=Long.parseLong(d[idx++]);if(tc>0)out.append("\n\n");out.append(kth(n,k));}System.out.print(out);}}
